452	const char* Class::GetDescriptor(std::string* storage) {
453	    uint64_t dim = 0u;
454	    Class* klass = this;
455	    Class tmp = 0x0;
456	
457	    while (klass->Ptr() && klass->IsArrayClass()) {
458	        ++dim;
459	        tmp = klass->GetComponentType();
460	        klass = &tmp;
461	    }
462	
463	    if (klass->IsProxyClass()) {
464	        *storage = DotToDescriptor(klass->GetName().ToModifiedUtf8().c_str());
465	    } else {
466	        const char* descriptor;
467	        if (klass->IsPrimitive()) {
468	            descriptor = Primitive::Descriptor(klass->GetPrimitiveType());
469	        } else {
470	            DexFile& dex_file = klass->GetDexFile();
471	            dex::TypeId type_id = dex_file.GetTypeId(klass->GetDexTypeIndex());
472	            descriptor = dex_file.GetTypeDescriptor(type_id);
473	        }
474	        if (dim == 0x0) {
475	            return descriptor;
476	        }
477	        *storage = descriptor;
478	    }
479	    storage->insert(0u, dim, '[');
480	    return storage->c_str();
481	}
